String greeting = "Hello";
greeting = greeting + " World";
System.out.println(greeting); // Hello World

String original = "java";
String upper = original.toUpperCase();

System.out.println(original); // java  -- unchanged!
System.out.println(upper);    // JAVA  -- a brand new String

String result = "";
for (int i = 1; i <= 5; i++) {
    result = result + i; // creates a NEW String every single iteration
}
System.out.println(result); // 12345

String a = "hello";
String b = "hello";
String c = new String("hello");

System.out.println(a == b);        // true (often, due to String interning)
System.out.println(a == c);        // false
System.out.println(a.equals(c));   // true

public class Main {
    public static void main(String[] args) {
        String password = "secret123";
        String userInput = "secret123";

        if (password.equals(userInput)) {
            System.out.println("Access granted");
        } else {
            System.out.println("Access denied");
        }
    }
}

